<script>
(function () {
    function disableCardLinks() {
        var selectors = [
            '.wpr-magazine-grid a',
            '.wpr-magazine-grid [data-url]',
            '.wpr-grid a',
            '.wpr-grid [data-url]',
            '.wpr-posts a',
            '.wpr-posts [data-url]',
            '.wpr-post-title a',
            '.wpr-post-media a',
            '.elementor-posts-container a',
            '.elementor-posts-container [data-url]',
            '.eael-post-grid a',
            '.eael-post-grid [data-url]',
            '.elementor-widget-posts a',
            '.elementor-widget-posts [data-url]'
        ];

        document.querySelectorAll(selectors.join(',')).forEach(function (item) {
            item.removeAttribute('href');
            item.removeAttribute('data-url');
            item.removeAttribute('onclick');
            item.setAttribute('aria-disabled', 'true');
        });
    }

    disableCardLinks();
    document.addEventListener('DOMContentLoaded', disableCardLinks);
})();
