-btn whitespace--normal" id="" aria-disabled="true" data-card-link-removed="true"> Read More <i aria-hidden="true" class="icon icon-chevron-right"></i> </a></div></div><!-- .elementskit-post-body END --></div></div><div class="col-lg-6 col-md-6"><div class="elementskit-post-image-card"><div class="elementskit-entry-header"> <a aria-disabled="true" data-card-link-removed="true" class="elementskit-entry-thumb"> <img src="{{ asset('asset/insights/wp-content/uploads/2024/09/Joshua-Duerksen-Secures-First-Formula-2-Sprint-Race-Win-in-Baku-1024x683.jpeg') }}" alt="Joshua Duerksen Secures First Formula 2 Sprint Race Win in Baku"> </a><!-- .elementskit-entry-thumb END --><div class="elementskit-meta-lists elementskit-style-tag"><div class="elementskit-single-meta triangle_left"><span class="elementskit-meta-wraper"><strong>16</strong>Sep</span></div></div></div><!-- .elementskit-entry-header END --><div class="elementskit-post-body ekit-highlight-border"><div class="post-meta-list"></div><h2 class="entry-title"> <a aria-disabled="true" data-card-link-removed="true"> Joshua Duerksen Secures First Formula 2 Sprint Race Win in Baku </a></h2><p>Formula 2 team AIX Racing celebrates another major success! In today&#8217;s sprint race on the streets of Baku in Azerbaijan, our driver Joshua Duerksen secured victory after starting from P4.&hellip;</p><div class="btn-wraper"> <a class="elementskit-btn whitespace--normal" id="" aria-disabled="true" data-card-link-removed="true"> Read More <i aria-hidden="true" class="icon icon-chevron-right"></i> </a></div></div><!-- .elementskit-post-body END --></div></div><div class="col-lg-6 col-md-6"><div class="elementskit-post-image-card"><div class="elementskit-entry-header"> <a aria-disabled="true" data-card-link-removed="true" class="elementskit-entry-thumb"> <img src="{{ asset('asset/insights/wp-content/uploads/2024/09/Goodbye-to-the-F3-class-of-2024-1024x682.jpeg') }}" alt="Goodbye to the F3 class of 2024"> </a><!-- .elementskit-entry-thumb