btn-wraper"> <a class="elementskit-btn whitespace--normal" id="" aria-disabled="true" data-card-link-removed="true"> Read More <i aria-hidden="true" class="icon icon-chevron-right"></i> </a></div></div><!-- .elementskit-post-body END --></div></div><div class="col-lg-6 col-md-6"><div class="elementskit-post-image-card"><div class="elementskit-entry-header"> <a aria-disabled="true" data-card-link-removed="true" class="elementskit-entry-thumb"> <img src="{{ asset('asset/insights/wp-content/uploads/2024/07/Spa-Francorchamps-1024x576.webp') }}" alt="AIX Racing Battles Wet Conditions at Spa Francorchamps"> </a><!-- .elementskit-entry-thumb END --><div class="elementskit-meta-lists elementskit-style-tag"><div class="elementskit-single-meta triangle_left"><span class="elementskit-meta-wraper"><strong>30</strong>Jul</span></div></div></div><!-- .elementskit-entry-header END --><div class="elementskit-post-body ekit-highlight-border"><div class="post-meta-list"></div><h2 class="entry-title"> <a aria-disabled="true" data-card-link-removed="true"> AIX Racing Battles Wet Conditions at Spa Francorchamps </a></h2><p>Over the weekend at the Spa Francorchamps Circuit in Belgium, the AIX Racing team persevered through challenging wet conditions in the FIA Formula 2 and FIA Formula 3 Championship.Stay tuned&hellip;</p><div class="btn-wraper"> <a class="elementskit-btn whitespace--normal" id="" aria-disabled="true" data-card-link-removed="true"> Read More <i aria-hidden="true" class="icon icon-chevron-right"></i> </a></div></div><!-- .elementskit-post-body END --></div></div><div class="col-lg-6 col-md-6"><div class="elementskit-post-image-card"><div class="elementskit-entry-header"> <a aria-disabled="true" data-card-link-removed="true" class="elementskit-entry-thumb"> <img src="{{ asset('asset/insights/wp-content/uploads/2024/07/Menchaca-and-Siebert-1024x685.webp') }}" alt="Strong Performance by Menchaca and Siebert at Paul Ricard"> </a><!-- .elementskit-entry-thumb END --><div class